mapper.select:
SELECT * FROM record_award
WHERE student_id = #{studentId}
ORDER BY award_date DESC

mapper.insert:
INSERT INTO record_award (
    student_id, award_name, award_level, issuing_authority, award_date, description, cert_file, audit_status
) VALUES (
    #{studentId}, #{awardName}, #{awardLevel}, #{issuingAuthority}, #{awardDate}, #{description}, #{certFile}, #{auditStatus}
)

mapper.update:
UPDATE record_award
award_name = #{awardName}, award_level = #{awardLevel}, issuing_authority = #{issuingAuthority}, award_date = #{awardDate}, description = #{description}, cert_file = #{certFile}, audit_status = #{auditStatus}
WHERE id = #{id}
